                    "color": "#F5F0E8",
                    "name": "Off White"
                },
                {
                    "slug": "gray",
                    "color": "#B0A99A",
                    "name": "Gray"
                },
                {
                    "slug": "dark-stone",
                    "color": "#3A3632",
                    "name": "Dark Stone"
                },
                {
                    "slug": "warm-black",
                    "color": "#181614",
                    "name": "Warm Black"
                }
            ],
            "gradients": [
                {
                    "slug": "charcoal-to-deep",
                    "gradient": "linear-gradient(180deg, #2B2B2B 0%, #1E1E1E 100%)",
                    "name": "Charcoal to Deep"
                },
                {
                    "slug": "stone-fade",
                    "gradient": "linear-gradient(180deg, #3A3632 0%, #2B2B2B 100%)",
                    "name": "Stone Fade"
                },
                {
                    "slug": "amber-glow",
                    "gradient": "linear-gradient(135deg, rgba(200,169,110,0.15) 0%, transparent 60%)",
                    "name": "Amber Glow"
                }
            ]
        },
        "typography": {
            "fontFamilies": [
                {
                    "fontFamily": "'Playfair Display', Georgia, 'Times New Roman', serif",
                    "slug": "heading",
                    "name": "Playfair Display"
                },
                {
                    "fontFamily": "'Jost', 'Helvetica Neue', Helvetica, Arial, sans-serif",
                    "slug": "body",
                    "name": "Jost"
                }
            ],
            "fontSizes": [
                {
                    "slug": "small",
                    "size": "0.8125rem",
                    "name": "Small"
                },
                {
                    "slug": "medium",
                    "size": "1rem",
                    "name": "Medium"
                },
                {
                    "slug": "large",
                    "size": "1.25rem",
                    "name": "Large"
                },
                {
                    "slug": "x-large",
                    "size": "1.75rem",
                    "name": "X-Large"
                },
                {
                    "slug": "xx-large",
                    "size": "2.25rem",
                    "name": "XX-Large"
                },
                {
                    "slug": "display",
                    "size": "clamp(2.75rem, 6vw, 3.5rem)",
                    "name": "Display"
                }
            ]
        },
        "spacing": {
            "units": ["px", "em", "rem", "vh", "vw", "%"],
            "spacingSizes": [
                {
                    "slug": "10",
                    "size": "0.5rem",
                    "name": "Tiny"
                },
                {
                    "slug": "20",
                    "size": "1rem",
                    "name": "Small"
                },
                {
                    "slug": "30",
                    "size": "1.5rem",
                    "name": "Medium"
                },
                {
                    "slug": "40",
                    "size": "2.5rem",
                    "name": "Large"
                },
                {
                    "slug": "50",
                    "size": "4rem",
                    "name": "X-Large"
                },
                {
                    "slug": "60",
                    "size": "6rem",
                    "name": "XX-Large"
                },
                {
                    "slug": "70",
                    "size": "8rem",
                    "name": "Huge"
                }
            ]
        },
        "custom": {
            "lineHeight": {
                "body": 1.6,
                "heading": 1.15
            }
        }
    },
    "styles": {
        "color": {
            "background": "#2B2B2B",
            "text": "#E8E0D0"
        },
        "typography": {
            "fontFamily": "'Jost', 'Helvetica Neue', Helvetica, Arial, sans-serif",
            "fontSize": "1rem",
            "fontWeight": "300",
            "lineHeight": "1.6",
            "letterSpacing": "0.02em"
        },
        "spacing": {
            "blockGap": "0"
        },
        "elements": {
            "heading": {
                "typography": {
                    "fontFamily": "'Playfair Display', Georgia, 'Times New Roman', serif",
                    "fontWeight": "500",
                    "lineHeight": "1.15",
                    "letterSpacing": "-0.01em"
                },
                "color": {
                    "text": "#F5F0E8"
                }
            },
            "h1": {
                "typography": {
                    "fontSize": "clamp(2.75rem, 6vw, 3.5rem)"
                }
            },
            "h2": {
                "typography": {
                    "fontSize": "2.25rem"
                }
            },
            "h3": {
                "typography": {
                    "fontSize": "1.75rem"
                }
            },
            "h4": {
                "typography": {
                    "fontSize": "1.25rem"
                }
            },
            "link": {
                "color": {
                    "text": "#C8A96E"
                },
                ":hover": {
                    "color": {
                        "text": "#F5F0E8"
                    }
                }
            },
            "button": {
                "color": {
                    "background": "#C8A96E",
                    "text": "#2B2B2B"
                },
                "typography": {
                    "fontFamily": "'Jost', 'Helvetica Neue', Helvetica, Arial, sans-serif",
                    "fontWeight": "400",
                    "letterSpacing": "0.12em",
                    "textTransform": "uppercase",
                    "fontSize": "0.8125rem"
                },
                "border": {
                    "radius": "0"
                },
                ":hover": {
                    "color": {
                        "background": "#F5F0E8",
                        "text": "#2B2B2B"
                    }
                }
            }
        },
        "blocks": {
            "core/separator": {
                "color": {
                    "text": "rgba(232, 224, 208, 0.12)"
                },
                "border": {
                    "color": "rgba(232, 224, 208, 0.12)"
                }
            },
            "core/quote": {
                "typography": {
                    "fontFamily": "'Playfair Display', Georgia, 'Times New Roman', serif",
                    "fontStyle": "italic",
                    "fontSize": "1.25rem"
                },
                "color": {
                    "text": "#F5F0E8"
                },
                "border": {
                    "left": {
                        "color": "#C8A96E",
                        "width": "2px",
                        "style": "solid"
                    }
                }
            }
        }
    },
    "templateParts": [
        {
            "name": "header",
            "title": "Header",
            "area": "header"
        },
        {
            "name": "footer",
            "title": "Footer",
            "area": "footer"
        }
    ]
}

/**
 * Theme Assets Editor Rewrite
 *
 * This script rewrites URLs in block attributes that start with 'theme:./'
 * to point to the correct theme assets.
 * It allows blocks in templates to reference theme assets using relative paths in the editor.
**/
(function (wp) {
	const base = window.THEME_ASSETS_BASE_URL || '';
	const prefix = 'theme:./';

	if (!wp?.hooks || !wp?.compose) return;

	const rewrite = (url) => {
		if (typeof url === 'string' && url.startsWith(prefix)) {
			const path = url.slice(prefix.length);
			return base + '/' + path;
		}
		return null;
	};

	// Recursively walk any value and rewrite all theme:./ URLs found in it.
	// Returns a new structure if anything changed, or null if nothing changed.
	const deepRewrite = (value) => {
		if (typeof value === 'string') {
			return rewrite(value);
		}
		if (Array.isArray(value)) {
			let changed = false;
			const result = value.map((item) => {
				const rewritten = deepRewrite(item);
				if (rewritten !== null) {
					changed = true;
					return rewritten;
				}
				return item;
			});
			return changed ? result : null;
		}
		if (value && typeof value === 'object') {
			let changed = false;
			const result = {};
			for (const key of Object.keys(value)) {
				const rewritten = deepRewrite(value[key]);
				if (rewritten !== null) {
					changed = true;
					result[key] = rewritten;
				} else {
					result[key] = value[key];
				}
			}
			return changed ? result : null;
		}
		return null;
	};

	wp.hooks.addFilter(
		'editor.BlockEdit',
		'theme-assets/rewrite-image-urls',
		wp.compose.createHigherOrderComponent((BlockEdit) => (props) => {
			const { attributes } = props;

			// Deep-rewrite all attributes to resolve any theme:./ URLs
			const rewrittenAttributes = deepRewrite(attributes);

			// Pass rewritten URLs to BlockEdit for display only, without persisting changes
			if (rewrittenAttributes) {
				const modifiedProps = {
					...props,
					attributes: rewrittenAttributes,
				};
				return wp.element.createElement(BlockEdit, modifiedProps);
			}

			return wp.element.createElement(BlockEdit, props);
		}, 'withThemeAssetsRewrite')
	);

})(window.wp);
